const meta   = $('Get file metadata').first().json;
const sheets = $('List worksheets').first().json.value || [];

// Priority order: the unit-status data sheet, then fallbacks
const PRIORITY = ['BOT - NEW ACTIVE LICENSEE', 'ALL UNITS', 'BOT'];

let targetSheet = null;
for (const name of PRIORITY) {
  const found = sheets.find(s => s.name.trim().toUpperCase() === name.toUpperCase());
  if (found) { targetSheet = found.name; break; }
}
if (!targetSheet) targetSheet = sheets[1]?.name || sheets[0]?.name || 'Sheet1';

const sheetEncoded = encodeURIComponent(targetSheet);
return [{ json: { sheetName: targetSheet, sheetEncoded, lastModified: meta.lastModifiedDateTime } }];

// Parse the Excel rows into a clean availability object
// Handles two possible column layouts:
//   Layout A (Unit # first): Unit # | Unit Type | Unit SF | Unit status | Company Name | ...
//   Layout B (Status first): Unit status | Company Name | Business Owner | Phone # | Email

const rows         = $('Read sheet data').first().json.values || [];
const lastModified = $('Pick sheet').first().json.lastModified;
const now          = new Date().toISOString();

const unitPattern = /^([A-Z]\d{2}|DOCK\s*\d+|P\d{2})$/i;

const units = [];
let headerLayout = null; // 'A' or 'B'
let sectionIdx   = 0;    // tracks which section header we last saw (WH/OFFICE/DOCK/TRAILER)
const SECTIONS   = ['WH','OFFICE','DOCK','TRAILER'];
let currentSectionType = 'WH';

for (const row of rows) {
  // Flatten each cell
  const cells = row.map(c => String(c === null || c === undefined ? '' : c).trim());
  const col0 = cells[0], col1 = cells[1], col2 = cells[2], col3 = cells[3], col4 = cells[4] || '';

  // Detect Layout A header: Unit # | Unit Type | Unit SF | Unit status | Company Name
  if (col0 === 'Unit #' && col1 === 'Unit Type' && col2 === 'Unit SF') {
    headerLayout = 'A';
    continue;
  }

  // Detect Layout B header: Unit status | Company Name | Business Owner | Phone # | Email
  if ((col0 === 'Unit status' || col0 === 'Unit Status') && col1 === 'Company Name') {
    headerLayout = 'B';
    continue;
  }

  if (headerLayout === 'A') {
    const unitId = col0.replace(/\s+/g,'').toUpperCase();
    if (!unitPattern.test(unitId)) continue;
    const sfNum  = Number(String(col2).replace(/[^0-9]/g,'')) || 0;
    const uType  = col1.toUpperCase() || (unitId.startsWith('R') ? 'OFFICE' : unitId.startsWith('DOCK') ? 'DOCK' : unitId.startsWith('P') ? 'TRAILER' : 'WH');
    units.push({
      unit: unitId, type: uType, sf: sfNum,
      status: col3, tenant: (col4 && col4 !== 'HOLD') ? col4 : null,
      available: col3 === 'Vacant'
    });
  } else if (headerLayout === 'B') {
    const status  = col0;
    const company = col1;
    if (!status || (!['Occupied','Vacant','occupied','vacant'].includes(status) && company !== 'HOLD' && !company.startsWith('HOLD'))) continue;
    // Layout B has no unit ID or sf — record what we can
    const isAvail = status.toLowerCase() === 'vacant' || company === 'HOLD' || company.startsWith('HOLD');
    units.push({
      unit: '', type: currentSectionType, sf: 0,
      status: isAvail ? 'Vacant' : 'Occupied',
      tenant: (!isAvail && company && company !== 'HOLD') ? company : null,
      available: isAvail
    });
  }
}

// Build summary by type
function summarise(type) {
  const group = units.filter(u => u.type === type);
  const avail = group.filter(u => u.available);
  const totalSf = group.reduce((s, u) => s + u.sf, 0);
  const availSf = avail.reduce((s, u) => s + u.sf, 0);
  return {
    total_units:  group.length,
    avail_units:  avail.length,
    total_sf:     totalSf,
    avail_sf:     availSf,
    avail_pct:    totalSf > 0 ? Math.round(availSf / totalSf * 1000) / 10 : 0,
    available:    avail.map(u => ({ unit: u.unit, sf: u.sf, tenant: u.tenant }))
  };
}

const wh      = summarise('WH');
const office  = summarise('OFFICE');
const dock    = summarise('DOCK');
const trailer = summarise('TRAILER');

// Build Firestore document fields
function toFsStr(v) { return { stringValue: String(v) }; }
function toFsInt(v) { return { integerValue: String(Math.round(v)) }; }
function toFsDbl(v) { return { doubleValue: v }; }
function toFsBool(v){ return { booleanValue: v }; }
function toFsNull() { return { nullValue: null }; }

function unitToFs(u) {
  return {
    mapValue: {
      fields: {
        unit:      toFsStr(u.unit),
        type:      toFsStr(u.type),
        sf:        toFsInt(u.sf),
        status:    toFsStr(u.status),
        tenant:    u.tenant ? toFsStr(u.tenant) : toFsNull(),
        available: toFsBool(u.available)
      }
    }
  };
}

function summaryToFs(s) {
  return {
    mapValue: {
      fields: {
        total_units: toFsInt(s.total_units),
        avail_units: toFsInt(s.avail_units),
        total_sf:    toFsInt(s.total_sf),
        avail_sf:    toFsInt(s.avail_sf),
        avail_pct:   toFsDbl(s.avail_pct)
      }
    }
  };
}

const patchBody = {
  fields: {
    property:        toFsStr('2720 Pellissier'),
    address:         toFsStr('2720 Pellissier Place, City of Industry, CA 90601'),
    yardi_url:       toFsStr('https://apps.commercialcafe.com/dealmanager/content/#/app/property/356D10A0-0AF9-4FBD-BF37-031CB028FB87/floorplan'),
    sharepoint_url:  toFsStr('https://cubework365.sharepoint.com/sites/Cubework_PropertyManagement/Shared%20Documents/Pellissier%202720%2C%20CA/Property%20Associates%20Weekly%20Report/2720%20Pellissier.xlsx'),
    sheet_last_modified: toFsStr(lastModified),
    synced_at:       toFsStr(now),
    wh:              summaryToFs(wh),
    office:          summaryToFs(office),
    dock:            summaryToFs(dock),
    parking:         summaryToFs(trailer),
    units: {
      arrayValue: { values: units.map(unitToFs) }
    }
  }
};

return [{ json: { patchBody } }];
